export default function ClubOverview({
                                         news,
                                         members,
                                         pending,
                                         user,
                                         userLabel,
                                         canPostNews,
                                         canApprove,
                                         setNews
                                     }) {
    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    const postNews = async e => {
        e.preventDefault();
        const res = await fetch(`/api/clubs/${clubId}/news?requesterEmail=${user.email}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ title, content })
        });
        const body = await res.json();
        setNews(prev => [body, ...prev]);
        setTitle(""); setContent("");
    };

    return (
        <div className="club-grid">
            {/* LEFT: NEWS */}
            <div>
                <h3>Club News</h3>

                {canPostNews && (
                    <form onSubmit={postNews}>
                        <input value={title} onChange={e=>setTitle(e.target.value)} />
                        <textarea value={content} onChange={e=>setContent(e.target.value)} />
                        <button>Post</button>
                    </form>
                )}

                {news.map(n => (
                    <div key={n.id} className="card">
                        <strong>{n.title}</strong>
                        <p>{n.content}</p>
                    </div>
                ))}
            </div>

            {/* RIGHT: MEMBERS */}
            <div>
                <h3>Members</h3>
                {members.map(m => (
                    <div key={m.id}>
                        {userLabel(m.userId)} — {m.role}
                    </div>
                ))}

                <h3>Pending Requests</h3>
                {pending.length === 0 && <div>No pending requests.</div>}
            </div>
        </div>
    );
}
